// Merge Pre-Process Output into input_data
const task = $('JSON Parse').first().json;
const preOutput = $json;
const preConfig = task.extra?.pre_process || {};
const outputHandling = preConfig.output_handling || 'merge';

let mergedData = { ...task.data };

if (preOutput && !preOutput.error) {
  if (outputHandling === 'replace') {
    mergedData = preOutput;
  } else if (outputHandling === 'merge') {
    mergedData = { ...mergedData, ...preOutput };
  } else if (outputHandling === 'nested') {
    const fieldName = preConfig.nested_field_name || 'pre_output';
    mergedData[fieldName] = preOutput;
  }
}

return {
  ...task,
  data: mergedData,
  _pre_process_executed: true
};

// Handle Pre-Process Failure
const task = $('JSON Parse').first().json;
const preConfig = task.extra?.pre_process || {};
const onFailure = preConfig.on_failure || 'continue';

if (onFailure === 'abort') {
  throw new Error('Pre-process webhook failed: ' + JSON.stringify($json.error));
}

// Continue with original data
return {
  ...task,
  _pre_process_failed: true,
  _pre_process_error: $json.error
};

// Handle Post-Process result
const originalResult = $('Add AlongWith Attributes').first().json;
const postConfig = $('JSON Parse').first().json.extra?.post_process || {};
const onFailure = postConfig.on_failure || 'continue';

// If post-process failed but on_failure = 'continue', proceed with original result
if ($json.error && onFailure === 'abort') {
  throw new Error('Post-process webhook failed: ' + JSON.stringify($json.error));
}

// Return original result (post-process doesn't modify task output)
return {
  ...originalResult,
  _post_process_executed: true,
  _post_process_response: $json.error ? null : $json
};
